using Microsoft.AspNetCore.HttpOverrides;
using System.Net.Http;

var builder = WebApplication.CreateBuilder(args);

// Breaking change fix #1 — ValidateOnBuild/ValidateScopes now enabled in Development.
// A scoped IUserService captured inside a singleton CacheService is a captive-dependency
// bug that .NET 9 will surface at startup. Fix: register CacheService as scoped too.
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// Breaking change fix #2 — HttpClientFactory now uses SocketsHttpHandler by default.
// Casting PrimaryHandler to HttpClientHandler throws InvalidCastException in .NET 9.
// Fix: use ConfigurePrimaryHttpMessageHandler to set the handler type explicitly.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new HttpClientHandler { UseCookies = false });

// Breaking change fix #3 — HttpClientFactory header logging redaction.
// In .NET 9, all header values in Trace-level logs are redacted by default.
// Explicitly allowlist specific non-sensitive headers you need to see in logs.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h => h != "X-Request-Id" && h != "X-Correlation-Id"));

// Breaking change fix #4 — ForwardedHeadersMiddleware now ignores X-Forwarded-*
// headers from proxies not in KnownProxies or KnownNetworks.
// Add your trusted proxy addresses here.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: replace with your actual reverse-proxy address(es)
    options.KnownProxies.Add(System.Net.IPAddress.Loopback);
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

// Stub services (pre-existing; unchanged by migration)
public interface IUserService { }
public class UserService : IUserService { }
public interface ICacheService { }
public class CacheService(IUserService userService) : ICacheService { }

